-- Current digest drafts
SELECT id, weekStarting, status, statsSnapshot, LEFT(includedPostIds, 100) as postIds FROM community_digests ORDER BY id DESC LIMIT 3;

-- Bookings created this week (since Monday 19 May 2026)
SELECT COUNT(*) as bookings_this_week FROM bookings WHERE createdAt >= '2026-05-19 00:00:00';

-- Commission claims this week
SELECT COUNT(*) as claims_this_week, SUM(grossAmount) as total FROM commission_claims WHERE claimedAt >= '2026-05-19 00:00:00' AND status IN ('paid','awaiting_payment');

-- Check createdAt column type/sample
SELECT id, createdAt FROM bookings ORDER BY createdAt DESC LIMIT 3;

